css:
.wrapper-rt-rev-region {
  --rrr-surface: var(--block-bg-color, #15151A);
  --rrr-surface-raised: #1B1B22;
  --rrr-ink: var(--color-text, #F4F4F7);
  --rrr-muted: var(--color-gray-500, #8A8A96);
  --rrr-label: var(--color-gray-700, #C2C2CC);
  --rrr-line: var(--color-gray-200, rgba(255,255,255,.07));
  --rrr-accent: var(--color-primary, #FFD21E);
  --rrr-accent-2: var(--color-secondary, #FF3D8B);
  --rrr-glow: 0 0 24px -6px color-mix(in srgb, var(--rrr-accent, #FFD21E) 55%, transparent);
  container-type: inline-size;
  height: 100%;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  color: var(--rrr-ink);
  font-variant-numeric: tabular-nums;
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}
.wrapper-rt-rev-region .rrr-card {
  display: flex;
  flex-direction: column;
  height: 100%;
  box-sizing: border-box;
  background: var(--rrr-surface);
  border: 1px solid var(--rrr-line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .16s ease, background-color .16s ease, box-shadow .16s ease;
}
.wrapper-rt-rev-region .rrr-card:hover {
  background: var(--rrr-surface-raised);
  border-color: color-mix(in srgb, var(--rrr-accent, #FFD21E) 32%, var(--rrr-line));
}
.wrapper-rt-rev-region .rrr-head {
  margin: 0 0 14px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--rrr-line);
  min-width: 0;
}
.wrapper-rt-rev-region .rrr-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  margin: 0 0 7px;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--rrr-label);
}
.wrapper-rt-rev-region .rrr-eyebrow::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--rrr-accent);
  box-shadow: 0 0 7px color-mix(in srgb, var(--rrr-accent, #FFD21E) 65%, transparent);
}
.wrapper-rt-rev-region .rrr-title {
  margin: 0;
  font: 800 14px/1.25 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--rrr-ink);
  overflow-wrap: break-word;
  word-break: break-word;
}
.wrapper-rt-rev-region .rrr-sub {
  margin: 4px 0 0;
  font: 500 11px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--rrr-muted);
  overflow-wrap: break-word;
  word-break: break-word;
}
.wrapper-rt-rev-region .rrr-chart {
  flex: 1 1 auto;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 240px;
  overflow: hidden;
  border-radius: 10px;
  transition: box-shadow .16s ease, outline-color .16s ease;
}
.wrapper-rt-rev-region .rrr-chart:focus-visible {
  outline: 2px solid var(--rrr-accent, #FFD21E);
  outline-offset: 3px;
  box-shadow: var(--rrr-glow);
}
.wrapper-rt-rev-region .rrr-empty {
  margin: auto;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 14px;
  border: 1px solid var(--rrr-line);
  border-radius: 10px;
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--rrr-muted);
  text-align: center;
}
.wrapper-rt-rev-region .rrr-empty[hidden] {
  display: none;
}
.wrapper-rt-rev-region .rrr-empty::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--rrr-muted);
}
@media (prefers-reduced-motion: reduce) {
  .wrapper-rt-rev-region .rrr-card,
  .wrapper-rt-rev-region .rrr-chart { transition: none; }
}

@container (max-width: 720px) {
  .wrapper-rt-rev-region .rrr-card { padding: 14px 16px; }
  .wrapper-rt-rev-region .rrr-chart { min-height: 220px; }
}
@container (max-width: 480px) {
  .wrapper-rt-rev-region .rrr-card { padding: 13px 14px; }
  .wrapper-rt-rev-region .rrr-head { margin-bottom: 12px; padding-bottom: 10px; }
  .wrapper-rt-rev-region .rrr-eyebrow { letter-spacing: .1em; }
  .wrapper-rt-rev-region .rrr-title { font-size: 13px; }
  .wrapper-rt-rev-region .rrr-sub { font-size: 10.5px; }
  .wrapper-rt-rev-region .rrr-chart { min-height: 220px; }
}
@container (max-width: 340px) {
  .wrapper-rt-rev-region .rrr-card { padding: 11px 12px; }
  .wrapper-rt-rev-region .rrr-chart { min-height: 220px; }
}
